import styled from "styled-components";

export const ScrollLanding = styled.a`
  text-decoration: none;
  :active {
    color: currentColor;
  }
  :visited {
    color: currentColor;
  }
`;

export const ScrollUp = styled.a`
  top: 0;
  display: flex;
  min-height: 50vh;
  min-width: 100vw;
  text-decoration: none;
  :active {
    color: currentColor;
  }
  :visited {
    color: currentColor;
  }
`;

export const ScrollDown = styled.a`
  bottom: 0;
  display: flex;
  min-height: 50vh;
  min-width: 100vw;
  text-decoration: none;
  :active {
    color: currentColor;
  }
  :visited {
    color: currentColor;
  }
`;
